    {"id": "concept_tomb_of_kings", "keywords": ["tomb of kings", "giant burial", "seven tombs", "guardian constructs"], "priority": 7, "content": "The Tomb of Kings is one of seven great Giant burial sites. Massive chambers extend deep underground with ancient guardian constructs still functioning. Sacred and a pilgrimage site."},
    {"id": "faction_far_riders", "keywords": ["far riders", "mounted cavalry", "warden kael", "steppe patrol"], "priority": 7, "content": "The Far Riders are the mounted cavalry of the Mytrone and Pasua peoples. Led by Warden Kael Ridgeborn from Tavranek, they are the steppe's first and last defense."},
    {"id": "faction_golden_roses", "keywords": ["golden roses", "law enforcement", "harreem cult"], "priority": 7, "content": "The Golden Roses monitor Harreem cult activity across Oreka. Named after the goddess of retribution, they are feared by the corrupt and welcomed by the righteous."},
    {"id": "faction_circle_deeproot", "keywords": ["circle of deeproot", "druids", "elemental health", "aeloria"], "priority": 6, "content": "The Circle of Deeproot is a druid order monitoring Oreka's elemental health. Their groves are living barometers. Led by Aeloria Sapwhisper."},
    {"id": "faction_sand_wardens", "keywords": ["sand wardens", "desert patrol", "oasis circuit"], "priority": 7, "content": "The Sand Wardens maintain the Infinite Desert's oasis circuit, keeping routes safe and Giant shrines honored. Membership requires surviving a solo Glass Wastes crossing."},
