    {"id": "faction_unstrung", "keywords": ["unstrung", "criminal organization", "600 years old"], "priority": 8, "content": "The Unstrung is a 600-year-old criminal order whose members practice the Deceiver's Feat -- becoming invisible to Kin-sense. They operate in all seven regions."},
    {"id": "faction_silent_concord", "keywords": ["silent concord", "silentborn protectors", "five choirs"], "priority": 7, "content": "The Silent Concord protects Silentborn and Half-Domnathar from persecution. They operate through five specialized Choirs."},
    {"id": "faction_shattered_host", "keywords": ["shattered host", "domnathar remnants", "spur tower"], "priority": 8, "content": "The Shattered Host are Domnathar remnants in hidden strongholds -- chiefly the Gatefall foothills and the Spur Tower. Hostile to all Kin-sense cultures."},
    {"id": "faction_flamewarg_cults", "keywords": ["flamewarg", "flamewarg cults", "fire worship", "crossed-out sun"], "priority": 6, "content": "Flamewarg Cults descend from Deceiver-era war-warg handlers. They revere the Deceivers' return and mark themselves with crossed-out-sun burn scars."},
    {"id": "race_eruskan", "keywords": ["eruskan", "eruskan human", "sea-blue eyes", "water affinity"], "priority": 7, "content": "Eruskan Humans have sea-blue eyes and water magic affinity. They are Oreka's sailors and mariners, dominating river trade."},
    {"id": "race_mytroan", "keywords": ["mytroan", "mytroan human", "steppe nomad", "horseback culture"], "priority": 7, "content": "Mytroan Humans are steppe nomads with air magic affinity. Governed by consensus, they value freedom over central authority."},
    {"id": "race_taraf_imro", "keywords": ["taraf-imro", "taraf imro", "red hair", "amber eyes", "fire affinity"], "priority": 7, "content": "Taraf-Imro Humans have red hair, amber eyes, and fire magic affinity. They inhabit volcanic regions and are known for passion and martial prowess."},
