    {"id": "race_pekakarlik", "keywords": ["pekakarlik", "water dwarves", "boat-builders", "hydraulic engineers"], "priority": 7, "content": "Pekakarlik Dwarves have water affinity and are master boat-builders. They maintain river settlements and rebuilt Rivertop after the Shattering."},
    {"id": "race_rarozhki", "keywords": ["rarozhki", "volcanic dwarves", "forge-smiths", "embersteel"], "priority": 7, "content": "Rarozhki Dwarves are volcanic forge-smiths with fire affinity, concentrated in Kharazhad. They produce Embersteel weapons."},
